.darma-loader-uiverse-laser-duel-sparks { position: relative; width: 150px; height: 80px; }
.darma-loader-uiverse-laser-duel-sparks__blade {
  position: absolute;
  bottom: 16px;
  width: 8px;
  height: 62px;
  border-radius: 6px;
  background: #666666;
  transform-origin: bottom center;
}
.darma-loader-uiverse-laser-duel-sparks__blade::before {
  content: "";
  position: absolute;
  left: 2px;
  bottom: 12px;
  width: 4px;
  height: 0;
  border-radius: 999px;
  filter: blur(.3px);
  animation: darma-loader-uiverse-laser-duel-sparks-laserGrow 1.6s ease-in-out infinite;
}
.darma-loader-uiverse-laser-duel-sparks__left { left: 28px; transform: rotate(62deg); }
.darma-loader-uiverse-laser-duel-sparks__right { right: 28px; transform: rotate(-62deg); }
.darma-loader-uiverse-laser-duel-sparks__left::before { background: var(--loader-color, #22c55e); box-shadow: 0 0 12px var(--loader-color, #22c55e), 0 0 30px var(--loader-color, #22c55e); }
.darma-loader-uiverse-laser-duel-sparks__right::before { background: var(--loader-secondary-color, #ef4444); box-shadow: 0 0 12px var(--loader-secondary-color, #ef4444), 0 0 30px var(--loader-secondary-color, #ef4444); }
.darma-loader-uiverse-laser-duel-sparks__spark { position: absolute; left: 50%; top: 38px; width: 6px; height: 6px; border-radius: 50%; background: #ffffff; box-shadow: 0 0 14px #ffffff; opacity: 0; animation: darma-loader-uiverse-laser-duel-sparks-duelSpark 1.6s infinite; }
.darma-loader-uiverse-laser-duel-sparks__s2 { animation-delay: .15s; }
.darma-loader-uiverse-laser-duel-sparks__s3 { animation-delay: .3s; }
.darma-loader-uiverse-laser-duel-sparks__s4 { animation-delay: .45s; }
@keyframes darma-loader-uiverse-laser-duel-sparks-laserGrow { 0%,15% { height: 0; } 35%,75% { height: 72px; } 100% { height: 0; } }
@keyframes darma-loader-uiverse-laser-duel-sparks-duelSpark { 0%, 42%, 100% { transform: translate(0,0) scale(.2); opacity: 0; } 48% { opacity: 1; } 60% { transform: translate(calc((var(--x, 1)) * 28px), -24px) scale(1); opacity: 0; } }
.darma-loader-uiverse-laser-duel-sparks__s1 { --x: -1; } .darma-loader-uiverse-laser-duel-sparks__s2 { --x: 1; } .darma-loader-uiverse-laser-duel-sparks__s3 { --x: -.5; } .darma-loader-uiverse-laser-duel-sparks__s4 { --x: .5; }

